function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStage(stageName) {
  console.log('');
  console.log(`${COLORS.cyan}${'='.repeat(60)}${COLORS.reset}`);
  console.log(`${COLORS.cyan}  STAGE: ${stageName}${COLORS.reset}`);
  console.log(`${COLORS.cyan}${'='.repeat(60)}${COLORS.reset}`);
  console.log('');
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
  pipelineState.warnings.push(message);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const defaults = {
    stdio: 'pipe',
    encoding: 'utf-8',
    timeout: CONFIG.testTimeout,
    env: { ...process.env, FORCE_COLOR: '1' },
  };
  const opts = { ...defaults, ...options };

  logInfo(`Executing: ${command}`);

  try {
    const result = execSync(command, opts);
    return { success: true, output: result ? result.trim() : '' };
  } catch (error) {
    return {
      success: false,
      output: error.stdout ? error.stdout.toString().trim() : '',
      error: error.stderr ? error.stderr.toString().trim() : error.message,
      exitCode: error.status,
    };
  }
}

function execOrFail(command, errorMessage, options = {}) {
  const result = exec(command, options);
  if (!result.success) {
    logError(`${errorMessage}`);
    logError(`Command: ${command}`);
    logError(`Error: ${result.error || result.output}`);
    throw new Error(errorMessage);
  }
  return result;
}

function fileExists(filePath) {
  return fs.existsSync(filePath);
}

function readJson(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch {
    return null;
  }
}

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

function getElapsedTime(startTime) {
  const elapsed = Date.now() - startTime;
  if (elapsed < 1000) return `${elapsed}ms`;
  if (elapsed < 60000) return `${(elapsed / 1000).toFixed(1)}s`;
  return `${Math.floor(elapsed / 60000)}m ${((elapsed % 60000) / 1000).toFixed(0)}s`;
}

function generateChecksum(filePath) {
  const result = exec(`sha256sum ${filePath} 2>/dev/null || shasum -a 256 ${filePath}`);
  return result.success ? result.output.split(' ')[0] : '';
}

async function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function sendNotification(message, status = 'info') {
  if (!CONFIG.slackWebhook) return;

  const emoji = {
    info: 'ℹ️',
    success: '✅',
    failure: '❌',
    warning: '⚠️',
  };

  const payload = {
    text: `${emoji[status] || ''} *Pipeline ${status.toUpperCase()}*\n${message}`,
    attachments: [
      {
        color: status === 'success' ? '#36a64f' : status === 'failure' ? '#ff0000' : '#ffcc00',
        fields: [
          { title: 'Branch', value: pipelineState.branch, short: true },
          { title: 'Commit', value: pipelineState.commitHash.substring(0, 8), short: true },
          { title: 'Duration', value: getElapsedTime(pipelineState.startTime), short: true },
          { title: 'Target', value: CONFIG.deployTarget, short: true },
        ],
      },
    ],
  };

  try {
    const http = require('https');
    const url = new URL(CONFIG.slackWebhook);
    const data = JSON.stringify(payload);

    await new Promise((resolve, reject) => {
      const req = http.request(
        {
          hostname: url.hostname,
          path: url.pathname,
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Content-Length': data.length },
        },
        (res) => {
          res.on('data', () => {});
          res.on('end', resolve);
        }
      );
      req.on('error', reject);
      req.write(data);
      req.end();
    });
  } catch (error) {
    logWarning(`Failed to send notification: ${error.message}`);
  }
}

