async function runStage(name, fn) {
  logStage(name);
  const stageStart = Date.now();
  pipelineState.currentStage = name;

  const stageInfo = {
    name,
    startTime: stageStart,
    status: 'running',
    duration: 0,
  };
  pipelineState.stages.push(stageInfo);

  try {
    await fn();
    stageInfo.status = 'success';
    stageInfo.duration = Date.now() - stageStart;
    logSuccess(`Stage "${name}" completed in ${getElapsedTime(stageStart)}`);
  } catch (error) {
    stageInfo.status = 'failed';
    stageInfo.duration = Date.now() - stageStart;
    stageInfo.error = error.message;
    pipelineState.errors.push({ stage: name, error: error.message });
    logError(`Stage "${name}" failed after ${getElapsedTime(stageStart)}: ${error.message}`);
    throw error;
  }
}

