async function stagePreflightChecks() {
  // Check Node.js version
  const nodeVersion = process.version;
  logInfo(`Node.js version: ${nodeVersion}`);

  const majorVersion = parseInt(nodeVersion.slice(1).split('.')[0]);
  if (majorVersion < parseInt(CONFIG.nodeVersion)) {
    throw new Error(
      `Node.js ${CONFIG.nodeVersion}+ required, found ${nodeVersion}`
    );
  }

  // Get git info
  const commitResult = exec('git rev-parse HEAD');
  if (commitResult.success) {
    pipelineState.commitHash = commitResult.output;
    logInfo(`Commit: ${pipelineState.commitHash}`);
  }

  const branchResult = exec('git rev-parse --abbrev-ref HEAD');
  if (branchResult.success) {
    pipelineState.branch = branchResult.output;
    logInfo(`Branch: ${pipelineState.branch}`);
  }

  const messageResult = exec('git log -1 --pretty=%B');
  if (messageResult.success) {
    pipelineState.commitMessage = messageResult.output;
    logInfo(`Message: ${pipelineState.commitMessage}`);
  }

  // Check for required files
  const requiredFiles = ['package.json'];
  for (const file of requiredFiles) {
    if (!fileExists(file)) {
      throw new Error(`Required file not found: ${file}`);
    }
  }

  // Check for package-lock.json or yarn.lock
  const hasPackageLock = fileExists('package-lock.json');
  const hasYarnLock = fileExists('yarn.lock');
  const hasPnpmLock = fileExists('pnpm-lock.yaml');

  if (!hasPackageLock && !hasYarnLock && !hasPnpmLock) {
    logWarning('No lock file found. Consider committing a lock file for reproducible builds.');
  }

  // Detect package manager
  if (hasPnpmLock) {
    pipelineState.packageManager = 'pnpm';
  } else if (hasYarnLock) {
    pipelineState.packageManager = 'yarn';
  } else {
    pipelineState.packageManager = 'npm';
  }
  logInfo(`Package manager: ${pipelineState.packageManager}`);

  // Check disk space
  const diskResult = exec("df -h . | tail -1 | awk '{print $5}'");
  if (diskResult.success) {
    const usage = parseInt(diskResult.output);
    if (usage > 90) {
      logWarning(`Disk usage is at ${usage}%`);
    }
  }

  // Validate environment for deployment
  if (CONFIG.deployTarget === 'production' && !CONFIG.dryRun) {
    if (!CONFIG.deployHost) {
      logWarning('DEPLOY_HOST not set. Deployment will be skipped.');
    }
  }

  // Check for skip flags in commit message
  if (pipelineState.commitMessage.includes('[skip ci]') || pipelineState.commitMessage.includes('[ci skip]')) {
    logWarning('Commit message contains [skip ci]. Exiting.');
    process.exit(0);
  }

  logSuccess('Preflight checks passed');
}

async function stageInstallDependencies() {
  const pm = pipelineState.packageManager;
  const cacheKey = generateChecksum(
    pm === 'pnpm' ? 'pnpm-lock.yaml' : pm === 'yarn' ? 'yarn.lock' : 'package-lock.json'
  );

  logInfo(`Lock file checksum: ${cacheKey.substring(0, 16)}...`);

  // Clean install for CI
  if (fs.existsSync('node_modules')) {
    logInfo('Removing existing node_modules for clean install...');
    exec('rm -rf node_modules');
  }

  let installCmd;
  switch (pm) {
    case 'pnpm':
      installCmd = 'pnpm install --frozen-lockfile --prefer-offline';
      break;
    case 'yarn':
      installCmd = 'yarn install --frozen-lockfile --prefer-offline --non-interactive';
      break;
    default:
      installCmd = 'npm ci --prefer-offline --no-audit --no-fund';
  }

  logInfo(`Installing dependencies with: ${installCmd}`);
  execOrFail(installCmd, 'Failed to install dependencies', {
    stdio: 'inherit',
    timeout: 300000, // 5 minutes
  });

  // Verify node_modules
  if (!fs.existsSync('node_modules')) {
    throw new Error('node_modules directory not found after install');
  }

  // Check for security vulnerabilities (non-blocking)
  logInfo('Checking for security vulnerabilities...');
  const auditCmd = pm === 'yarn' ? 'yarn audit --level high' : pm === 'pnpm' ? 'pnpm audit --audit-level high' : 'npm audit --audit-level=high';
  const auditResult = exec(auditCmd);
  if (!auditResult.success) {
    logWarning('Security vulnerabilities detected. Review audit output.');
    if (auditResult.output) {
      console.log(auditResult.output.substring(0, 500));
    }
  } else {
    logSuccess('No high/critical vulnerabilities found');
  }
}

